INSERT INTO `pois_localizeddata` (`id`, `lang_code`, `name`, `description`, `audio`, `poi_id`, `created_at`, `updated_at`) VALUES
	('003a81d4-60eb-41c7-b9ee-4fd24fe02ed4', 'vi', 'Dinh Độc Lập', 'Dinh Độc Lập là một công trình kiến trúc lịch sử mang tính biểu tượng của Thành phố Hồ Chí Minh, từng là nơi ở và làm việc của Tổng thống Việt Nam Cộng hòa. Nơi đây chứng kiến nhiều sự kiện lịch sử quan trọng, đặc biệt là khoảnh khắc xe tăng húc đổ cổng chính vào ngày 30 tháng 4 năm 1975. Hiện nay, dinh được bảo tồn nguyên vẹn và mở cửa thường xuyên cho du khách trong và ngoài nước đến tham quan.', 'http://localhost:8000/media/pois/e73cc8a6-d51a-4770-b19c-825db407a174/audio_vi', 'e73cc8a6-d51a-4770-b19c-825db407a174', '2026-04-07 02:07:44.884195', '2026-04-07 02:35:46.418633'),
	('06368591-db32-42c7-b7b5-4b5a5f9dddbc', 'vi', 'Bảo tàng Chứng tích Chiến tranh', 'Bảo tàng Chứng tích Chiến tranh là nơi lưu giữ và trưng bày những tư liệu, hiện vật về hậu quả tàn khốc của các cuộc chiến tranh tại Việt Nam. Nơi đây mang đến cho du khách cái nhìn chân thực, sâu sắc về lịch sử và thông điệp mạnh mẽ về khát vọng hòa bình. Đây là một trong những bảo tàng thu hút đông đảo lượng khách quốc tế nhất khi đến thăm Thành phố Hồ Chí Minh.', 'http://localhost:8000/media/pois/5594af38-0e8e-4aa0-a726-120e08102948/audio_vi', '5594af38-0e8e-4aa0-a726-120e08102948', '2026-04-07 02:12:08.660990', '2026-04-07 02:30:45.980710'),
	('160dee0b-17d9-469f-905c-039b191f2659', 'zh', '西贡动植物园', '西贡动植物园是世界上最古老的植物园和动物园之一，位于第一区的中心地带。它拥有广阔的绿地，保存着数千种不同的动物和稀有的古树种。这个校园不仅是家庭周末理想的娱乐场所，也是青少年有益的天然教育场所。', 'http://localhost:8000/media/pois/0e04de5e-bb05-45ee-b7c5-8050e6fbdbac/audio_zh.mp3', '0e04de5e-bb05-45ee-b7c5-8050e6fbdbac', '2026-04-07 10:33:52.631031', '2026-04-07 10:33:52.631031'),
	('352072c9-cc36-4bf4-a3b0-19cc08791417', 'vi', 'Chợ Bến Thành', 'Chợ Bến Thành không chỉ là khu chợ bán lẻ quy mô lớn mà còn là biểu tượng văn hóa và giao thương lâu đời của Sài Gòn. Công trình nổi bật với tháp đồng hồ đặc trưng ở cửa Nam, bên trong bày bán đa dạng các mặt hàng từ quần áo, đồ thủ công mỹ nghệ đến đặc sản địa phương. Trải qua hơn một thế kỷ, ngôi chợ này vẫn giữ được sức sống mãnh liệt và là điểm dừng chân không thể thiếu của du khách.', 'http://localhost:8000/media/pois/18d539c2-8237-4238-96b0-6b5285afbf4b/audio_vi', '18d539c2-8237-4238-96b0-6b5285afbf4b', '2026-04-07 02:14:06.317926', '2026-04-07 02:28:37.050796'),
	('39fae402-9014-44a9-a289-858e1832da02', 'en', 'Phở Hòa Pasteur', 'Phở Hòa on Pasteur Street is one of the oldest and most famous pho restaurants in Saigon, operating for over 50 years. The broth here is simmered from beef bones for many hours, bringing a naturally sweet and rich traditional flavor. The restaurant is always bustling with customers every day and is an unmissable culinary destination for both locals and international tourists.', 'http://localhost:8000/media/pois/67573322-bd75-491e-bbb7-444685596429/audio_en', '67573322-bd75-491e-bbb7-444685596429', '2026-04-07 09:53:25.794624', '2026-04-07 09:53:25.794624'),
	('59284f6b-687a-45b0-a0eb-ca64fe0a639e', 'en', 'War Remnants Museum', 'The War Remnants Museum preserves and displays documents and artifacts about the devastating consequences of wars in Vietnam. It offers visitors a realistic and profound insight into history and a powerful message of yearning for peace. It is one of the most visited museums by international tourists when visiting Ho Chi Minh City.', 'http://localhost:8000/media/pois/5594af38-0e8e-4aa0-a726-120e08102948/audio_en', '5594af38-0e8e-4aa0-a726-120e08102948', '2026-04-07 09:51:50.200158', '2026-04-07 09:51:50.200158'),
	('749ed179-7006-4f0c-b75f-3a37185a41e4', 'vi', 'Chung cư 42 Nguyễn Huệ', 'Chung cư 42 Nguyễn Huệ là một tòa nhà chung cư cũ được cải tạo lại, quy tụ hàng chục quán cà phê, trà sữa và cửa hàng thời trang độc đáo. Từ ban công của các quán nước, khách hàng có thể ngắm trọn vẹn phố đi bộ sầm uất và tận hưởng không khí nhộn nhịp của trung tâm thành phố. Đây là điểm check-in quen thuộc và mang đậm phong cách sống hiện đại của giới trẻ Sài Thành.', 'http://localhost:8000/media/pois/5c52d4d3-1e43-4d2d-9c5f-d568cb0da6f6/audio_vi', '5c52d4d3-1e43-4d2d-9c5f-d568cb0da6f6', '2026-04-07 02:13:22.557645', '2026-04-07 02:33:12.088418'),
	('7a08d0fa-d9a6-4508-b2d0-f2ea5278d0e4', 'en', 'Ben Thanh Market', 'Ben Thanh Market is not only a large-scale retail market but also a long-standing cultural and trading symbol of Saigon. The building is distinguished by its iconic clock tower at the South Gate, offering a diverse range of goods from clothing, handicrafts, to local specialties. Having stood for over a century, this market retains its vibrant energy and is an indispensable stop for tourists.', 'http://localhost:8000/media/pois/18d539c2-8237-4238-96b0-6b5285afbf4b/audio_en', '18d539c2-8237-4238-96b0-6b5285afbf4b', '2026-04-07 09:39:45.453613', '2026-04-07 09:41:48.283189'),
	('7bf90744-9a6b-4c2a-8bd8-501678d7a9e5', 'ja', 'フォー・ホア・パストゥール', 'パストゥール通りにあるフォー・ホアは、50年以上営業しているサイゴンの最も古く、最も有名なフォー店の一つです。ここでは、牛の骨髄を長時間煮込んで作られたスープが、自然で甘く、伝統的な風味豊かな味わいを醸し出しています。この店は毎日多くの顧客で賑わっており、地元の人々や外国人観光客にとって見逃せないグルメスポットです。', 'http://localhost:8000/media/pois/67573322-bd75-491e-bbb7-444685596429/audio_ja', '67573322-bd75-491e-bbb7-444685596429', '2026-04-07 09:56:53.317099', '2026-04-07 09:56:53.318083'),
	('7e76508d-672b-49a7-8515-41801ed2f1d6', 'en', 'Thao Cam Vien', '', NULL, '0e04de5e-bb05-45ee-b7c5-8050e6fbdbac', '2026-04-07 07:07:39.095934', '2026-04-07 07:07:39.095934'),
	('829deece-21cc-4ffd-a7e9-63fdc2a0324b', 'fr', 'Thảo Cầm Viên Sài Gòn', 'Le Jardin botanique de Saïgon est l\'un des plus anciens jardins botaniques et zoos du monde, situé en plein cœur du district 1. Il offre un immense espace vert luxuriant, abritant des milliers d\'animaux divers et des espèces d\'arbres centenaires rares. Ce parc n\'est pas seulement une destination de loisirs idéale pour les familles le week-end, mais aussi un lieu d\'éducation à la nature enrichissant pour les jeunes.', 'http://localhost:8000/media/pois/0e04de5e-bb05-45ee-b7c5-8050e6fbdbac/audio_fr', '0e04de5e-bb05-45ee-b7c5-8050e6fbdbac', '2026-04-07 08:33:45.217256', '2026-04-07 08:33:45.218940'),
	('9dcd2071-4f7d-4d66-9b5f-8d3396474773', 'fr', 'Marché de Ben Thanh', 'Le marché Ben Thanh n\'est pas seulement un marché de détail à grande échelle, mais aussi un symbole culturel et commercial de longue date de Saigon. Le projet se distingue par sa tour de l\'horloge emblématique à la porte sud, à l\'intérieur de laquelle vend une variété d\'articles allant des vêtements à l\'artisanat en passant par les spécialités locales. Après plus d\'un siècle, ce marché conserve toujours sa vitalité et constitue une étape incontournable pour les touristes.', 'http://localhost:8000/media/pois/18d539c2-8237-4238-96b0-6b5285afbf4b/audio_fr.mp3', '18d539c2-8237-4238-96b0-6b5285afbf4b', '2026-04-07 10:44:00.124481', '2026-04-07 10:44:00.124481'),
	('a352f83a-a6f3-4240-b1b2-49f579269786', 'ja', 'ベンタイン市場', 'ベンタイン市場は大規模な小売市場であるだけでなく、サイゴンの長年にわたる文化と貿易のシンボルでもあります。このプロジェクトは、南門にある特徴的な時計塔で際立っており、その中には衣料品、手工芸品、地元の特産品に至るまで、さまざまな品物が販売されています。 1世紀以上経った今でもその活気を保っており、観光客にとって欠かせない市場となっています。', 'http://localhost:8000/media/pois/18d539c2-8237-4238-96b0-6b5285afbf4b/audio_ja.mp3', '18d539c2-8237-4238-96b0-6b5285afbf4b', '2026-04-07 10:46:41.230831', '2026-04-07 10:46:41.230831'),
	('b1991c08-2aa0-405b-8a53-dab732257eff', 'vi', 'Thảo Cầm Viên Sài Gòn', 'Thảo Cầm Viên Sài Gòn là một trong những công viên thực vật và vườn thú lâu đời nhất trên thế giới, tọa lạc ngay tại trung tâm Quận 1. Nơi đây sở hữu không gian xanh mát khổng lồ, bảo tồn hàng ngàn cá thể động vật đa dạng và các loài cây cổ thụ quý hiếm. Khuôn viên này không chỉ là địa điểm vui chơi giải trí cuối tuần lý tưởng cho các gia đình mà còn là nơi giáo dục thiên nhiên bổ ích cho giới trẻ.', 'http://localhost:8000/media/pois/0e04de5e-bb05-45ee-b7c5-8050e6fbdbac/audio_vi', '0e04de5e-bb05-45ee-b7c5-8050e6fbdbac', '2026-04-07 02:10:39.750357', '2026-04-07 02:15:35.395634'),
	('c589238e-4927-456b-a1a0-47eeda467e2f', 'vi', 'Bánh mì Huynh Hoa', 'Bánh mì Huynh Hoa được mệnh danh là tiệm bánh mì đắt và đông khách bậc nhất Sài Gòn, nổi tiếng với ổ bánh mì vô cùng đầy đặn. Lớp nhân bên trong cực kỳ chất lượng với vô số loại chả, thịt nguội, pate béo ngậy và chà bông mặn mà xếp lớp dày đặc. Dù luôn phải xếp hàng chờ đợi, hương vị đậm đà đặc trưng của tiệm vẫn khiến thực khách sẵn lòng chờ đợi để thưởng thức.', 'http://localhost:8000/media/pois/fed23e35-f318-4c39-9f46-e4581fe709ee/audio_vi', 'fed23e35-f318-4c39-9f46-e4581fe709ee', '2026-04-07 02:37:54.294829', '2026-04-07 03:30:14.382407'),
	('cbe9ea73-1766-4a46-aafc-3fb618c2b1c4', 'vi', 'Phở Hòa Pasteur', 'Phở Hòa trên đường Pasteur là một trong những quán phở lâu đời và nổi tiếng bậc nhất tại Sài Gòn với hơn 50 năm hoạt động. Nước dùng ở đây được ninh từ xương ống bò trong nhiều giờ, mang lại hương vị ngọt thanh tự nhiên và đậm đà hương vị truyền thống. Quán luôn tấp nập thực khách mỗi ngày và là địa chỉ ẩm thực không thể bỏ qua đối với cả người dân địa phương lẫn du khách quốc tế.', 'http://localhost:8000/media/pois/67573322-bd75-491e-bbb7-444685596429/audio_vi', '67573322-bd75-491e-bbb7-444685596429', '2026-04-07 02:08:48.535257', '2026-04-07 02:34:41.651602'),
	('e91374f3-3bfc-4f30-a81f-85790a9d45d7', 'ja', 'サイゴン動物園', 'サイゴン動植物園は、世界でも有数の歴史ある植物園・動物園であり、1区の中心部に位置しています。広大な緑地には、数千もの多様な動物と希少な古木が保護されています。この敷地は、家族連れにとって理想的な週末のレジャー施設であるだけでなく、若者にとって有益な自然教育の場でもあります。', NULL, '0e04de5e-bb05-45ee-b7c5-8050e6fbdbac', '2026-04-07 08:51:25.275700', '2026-04-07 10:35:00.670117');
