	('fed23e35-f318-4c39-9f46-e4581fe709ee', 'vi', 'http://127.0.0.1:8000/media/pois/fed23e35-f318-4c39-9f46-e4581fe709ee/image.png', 'food', 50, 10.771667, 106.6925, 'active', 'banh-mi-huynh-hoa', '2026-04-07 02:37:54.286652', '2026-04-07 02:37:54.286652');
INSERT INTO `tours_tour` (`id`, `name`, `description`, `created_at`, `updated_at`, `image`, `status`) VALUES
	('a5075f25-82ff-40c4-8350-5dd1e9b0a5d8', 'Thiên Nhiên Xanh và Tinh Hoa Ẩm Thực Sài Gòn', 'Bắt đầu ngày mới tràn đầy năng lượng với không gian xanh mát và hệ sinh thái đa dạng tại Thảo Cầm Viên Sài Gòn. Xuyên suốt hành trình dạo chơi, du khách sẽ được dừng chân để thưởng thức những món ăn mang tính biểu tượng của thành phố. Trải nghiệm nếm thử ổ Bánh mì Huynh Hoa đầy đặn và tô Phở Hòa Pasteur đậm đà chắc chắn sẽ làm hài lòng bất kỳ tín đồ ẩm thực nào.', '2026-04-07 02:39:02.507206', '2026-04-07 02:41:14.374174', 'http://localhost:8000/media/tours/a5075f25-82ff-40c4-8350-5dd1e9b0a5d8/image.jpg', 'published'),
	('b2d16d9b-d186-44c6-9ec1-452c5b4e4ba0', 'Sài Gòn Lịch Sử và Hiện Đại', 'Chuyến hành trình bắt đầu bằng việc khám phá những thăng trầm lịch sử của thành phố qua Dinh Độc Lập và Bảo tàng Chứng tích Chiến tranh. Sau buổi sáng đậm chất hoài niệm, du khách sẽ được thư giãn và ngắm nhìn nhịp sống nhộn nhịp từ các quán cà phê độc đáo tại Chung cư 42 Nguyễn Huệ. Đây là tour lý tưởng để cảm nhận sự giao thoa hoàn hảo giữa quá khứ và hiện tại của Sài Gòn.', '2026-04-07 02:38:36.574551', '2026-04-07 02:41:34.184906', 'http://localhost:8000/media/tours/b2d16d9b-d186-44c6-9ec1-452c5b4e4ba0/image.jpg', 'published'),
	('d64c039d-bc2d-40ed-9eda-7388595ae2d1', 'Dấu Ấn Sài Gòn Xưa', 'Hành trình ngắn đưa bạn ghé thăm những công trình kiến trúc và biểu tượng văn hóa lâu đời nhất của trung tâm thành phố. Du khách sẽ được dạo bước qua Chợ Bến Thành sầm uất với bề dày lịch sử hàng trăm năm, mua sắm đồ thủ công mỹ nghệ và tìm hiểu văn hóa giao thương địa phương. Sau đó, tiếp tục di chuyển đến Dinh Độc Lập để chiêm ngưỡng trọn vẹn kiến trúc độc đáo và không gian lịch sử hào hùng.', '2026-04-07 02:39:31.458520', '2026-04-07 02:40:20.152475', 'http://localhost:8000/media/tours/d64c039d-bc2d-40ed-9eda-7388595ae2d1/image.jpg', 'published');
